public class ShipmentHttpService : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentHttpService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<ShipmentDto>> GetAllShipmentsAsync(string? statusFilter = null, string? search = null)
    {
        var url = "/api/shipments";
        var query = new List<string>();
        if (!string.IsNullOrEmpty(statusFilter)) query.Add($"status={Uri.EscapeDataString(statusFilter)}");
        if (!string.IsNullOrEmpty(search)) query.Add($"search={Uri.EscapeDataString(search)}");
        if (query.Count > 0) url += "?" + string.Join("&", query);
        return await _http.GetFromJsonAsync<List<ShipmentDto>>(url) ?? [];
    }

    public async Task<List<ShipmentDto>> GetMyShipmentsAsync()
    {
        return await _http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments/mine") ?? [];
    }

    public async Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber)
    {
        return await _http.GetFromJsonAsync<ShipmentDto?>($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
    }

    public async Task UpdateStatusAsync(int id, string newStatus)
    {
        await _http.PutAsJsonAsync($"/api/shipments/{id}/status", new { Status = newStatus });
    }
}
```

### 6. Server-side implementation using EF Core

Create `ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;
using System.Security.Claims;
using Microsoft.AspNetCore.Http;

namespace ShipmentTracker.Services;

public class ShipmentServerService : IShipmentService
{
    private readonly ApplicationDbContext _db;
    private readonly IHttpContextAccessor _httpContextAccessor;

    public ShipmentServerService(ApplicationDbContext db, IHttpContextAccessor httpContextAccessor)
    {
        _db = db;
        _httpContextAccessor = httpContextAccessor;
    }

    public async Task<List<ShipmentDto>> GetAllShipmentsAsync(string? statusFilter = null, string? search = null)
    {
        var query = _db.Shipments.AsQueryable();
        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, out var status))
            query = query.Where(s => s.Status == status);
        if (!string.IsNullOrEmpty(search))
            query = query.Where(s => s.TrackingNumber.Contains(search) || s.Destination.Contains(search) || s.CustomerName.Contains(search));
        return await query.OrderByDescending(s => s.CreatedAt).Select(s => ToDto(s)).ToListAsync();
    }

    public async Task<List<ShipmentDto>> GetMyShipmentsAsync()
    {
        var userId = _httpContextAccessor.HttpContext?.User.FindFirstValue(ClaimTypes.NameIdentifier);
        if (string.IsNullOrEmpty(userId)) return [];
        return await _db.Shipments
            .Where(s => s.CustomerId == userId)
            .OrderByDescending(s => s.CreatedAt)
            .Select(s => ToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var s = await _db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return s == null ? null : ToDto(s);
    }

    public async Task UpdateStatusAsync(int id, string newStatus)
    {
        if (!Enum.TryParse<ShipmentStatus>(newStatus, out var status)) return;
        var shipment = await _db.Shipments.FindAsync(id);
        if (shipment != null)
        {
            shipment.Status = status;
            await _db.SaveChangesAsync();
        }
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status.ToString(),
        CreatedAt = s.CreatedAt,
        EstimatedDelivery = s.EstimatedDelivery,
        CustomerName = s.CustomerName,
        Notes = s.Notes
    };
}
```

