@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService

<PageTitle>All Shipments</PageTitle>

<h1>Shipments</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Search tracking #, destination, customer..."
               @bind="searchTerm" @bind:event="oninput" @onkeyup="HandleSearch" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter" @bind:after="LoadShipments">
            <option value="">All Statuses</option>
            <option value="Pending">Pending</option>
            <option value="PickedUp">Picked Up</option>
            <option value="InTransit">In Transit</option>
            <option value="OutForDelivery">Out for Delivery</option>
            <option value="Delivered">Delivered</option>
            <option value="Exception">Exception</option>
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-primary" @onclick="LoadShipments">
            <span class="bi bi-arrow-clockwise"></span> Refresh
        </button>
    </div>
</div>

@if (loading)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Customer</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in shipments)
            {
                <tr>
                    <td><strong>@s.TrackingNumber</strong></td>
                    <td>@s.CustomerName</td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td><span class="badge @GetStatusBadge(s.Status)">@FormatStatus(s.Status)</span></td>
                    <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width:auto;display:inline-block"
                                value="@s.Status" @onchange="e => UpdateStatus(s, e)">
                            <option value="Pending">Pending</option>
                            <option value="PickedUp">Picked Up</option>
                            <option value="InTransit">In Transit</option>
                            <option value="OutForDelivery">Out for Delivery</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Exception">Exception</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto> shipments = [];
    private string searchTerm = "";
    private string statusFilter = "";
    private bool loading = true;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        shipments = await ShipmentService.GetAllShipmentsAsync(statusFilter, searchTerm);
        loading = false;
    }

    private async Task HandleSearch()
    {
        await LoadShipments();
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        var newStatus = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newStatus) && newStatus != shipment.Status)
        {
            await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadge(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "PickedUp" => "bg-info",
        "InTransit" => "bg-primary",
        "OutForDelivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Exception" => "bg-danger",
        _ => "bg-secondary"
    };

    private static string FormatStatus(string status) => status switch
    {
        "PickedUp" => "Picked Up",
        "InTransit" => "In Transit",
        "OutForDelivery" => "Out for Delivery",
        _ => status
    };
}

